const b = $input.first().json.body || $input.first().json;
const allBinary = $input.first().binary || {};

let tasks = [];
try {
  tasks = JSON.parse(b.tasks || '[]');
} catch (_) {
  tasks = [];
}
if (!Array.isArray(tasks) || !tasks.length) {
  throw new Error('No tasks in payload — expected JSON array under field "tasks"');
}

const shared = {
  schedule_mode: b.schedule_mode || 'now',
  send_at: b.send_at || 'now',
  send_at_utc: b.send_at_utc || 'now',
  scope: b.scope || 'employee',
};

return tasks.map((t, idx) => {
  const emails = (Array.isArray(t.emails) ? t.emails : String(t.emails || '').split(/[,;]+/))
    .map(e => String(e).trim())
    .filter(e => /@/.test(e));
  const key = t.binary_key || ('file_' + (t.index != null ? t.index : idx));
  const fileBin = allBinary[key];
  return {
    json: {
      ...shared,
      task_index: idx,
      emails_array: emails,
      recipients_count: emails.length,
      subject: t.subject || 'תלוש שכר',
      body: t.body || '',
      body_html: t.body_html || ('<div dir="rtl">' + (t.body || '') + '</div>'),
      employee_number: t.employee_number || '',
      name: t.name || '',
      department: t.department || '',
      category: t.category || '',
      month: t.month || '',
      count: t.count || '',
      filename: t.filename || (fileBin && fileBin.fileName) || 'attachment.pdf',
    },
    binary: fileBin ? { data: fileBin } : {}
  };
});

const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const j = item.json;
  const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
  const base64 = buffer.toString('base64');
  out.push({
    json: {
      ...j,
      draft_body: {
        subject: j.subject,
        body: { contentType: 'HTML', content: j.body_html },
        toRecipients: [{ emailAddress: { address: j.current_email } }],
        attachments: [{
          '@odata.type': '#microsoft.graph.fileAttachment',
          name: j.filename,
          contentBytes: base64
        }],
        singleValueExtendedProperties: [{
          id: 'SystemTime 0x3FEF',
          value: j.send_at_utc
        }]
      }
    }
  });
}
return out;

const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const j = item.json;
  const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
  const base64 = buffer.toString('base64');
  out.push({
    json: {
      ...j,
      sendmail_body: {
        message: {
          subject: j.subject,
          body: { contentType: 'HTML', content: j.body_html },
          toRecipients: [{ emailAddress: { address: j.current_email } }],
          attachments: [{
            '@odata.type': '#microsoft.graph.fileAttachment',
            name: j.filename,
            contentBytes: base64
          }]
        },
        saveToSentItems: true
      }
    }
  });
}
return out;

const items = $input.all();
const split = $('Split Out').all();
const failures = [];
let ok = 0;
for (let i = 0; i < items.length; i++) {
  const out = items[i] && items[i].json || {};
  const errMsg = out.error || (items[i] && items[i].error && items[i].error.message);
  if (errMsg) {
    const orig = (split[i] && split[i].json) || {};
    failures.push({
      email: orig.current_email || 'unknown',
      filename: orig.filename || '',
      error: typeof errMsg === 'string' ? errMsg : String(errMsg)
    });
  } else {
    ok++;
  }
}
const scheduleMode = (split[0] && split[0].json && split[0].json.schedule_mode) || 'now';
const total = items.length;
const status = failures.length === 0
  ? (scheduleMode === 'scheduled' ? 'scheduled' : 'sent')
  : (ok === 0 ? 'error' : 'partial');
return [{
  json: {
    status: status,
    sent: scheduleMode === 'now' ? ok : 0,
    scheduled: scheduleMode === 'scheduled' ? ok : 0,
    failed: failures.length,
    total: total,
    failures: failures,
    schedule_mode: scheduleMode,
    send_at_utc: (split[0] && split[0].json && split[0].json.send_at_utc) || 'now',
    scope: (split[0] && split[0].json && split[0].json.scope) || 'employee',
    recipients_count: total
  }
}];
